const raw = $input.first().json;
let fullInput = '';
if (raw.query && typeof raw.query === 'string') fullInput = raw.query.trim();
else if (raw.chatInput && typeof raw.chatInput === 'string') fullInput = raw.chatInput.trim();
else if (raw.airtable_id) fullInput = raw.airtable_id.trim();
else {
  for (const [k, v] of Object.entries(raw)) {
    if (typeof v === 'string' && v.length > 3) { fullInput = v.trim(); break; }
  }
}
const idMatch = fullInput.match(/(rec[A-Za-z0-9]+|TEST_[A-Za-z0-9_]+)/);
const airtableId = idMatch ? idMatch[1] : '';
const extraContext = fullInput.replace(airtableId, '').replace(/^\s*\|\s*/, '').trim();
return [{ json: { airtable_id: airtableId, extra_context: extraContext, has_id: airtableId.length > 0 } }];

const sonnetResp = $('🧠 Claude Sonnet (CV)').first().json;
let result = {};
try {
  const text = sonnetResp.content?.[0]?.text || '{}';
  // Nettoyer : enlever markdown, texte avant/après le JSON
  let cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const firstBrace = cleaned.indexOf('{');
  const lastBrace = cleaned.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) cleaned = cleaned.substring(firstBrace, lastBrace + 1);
  result = JSON.parse(text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim());
} catch(e) {
  return [{ json: { response: 'Erreur analyse CV: ' + e.message, phase: 'error', needs_critique: false } }];
}

// === PHASE COLLECT ===
if (result.phase === 'collect') {
  let resp = 'PHASE COLLECTE\n\n';
  resp += 'Trouvé : ' + JSON.stringify(result.data_found || {}) + '\n';
  resp += 'Manque : ' + (result.missing || []).join(', ') + '\n\n';
  resp += 'QUESTION À POSER (telle quelle) :\n' + (result.next_question || '') + '\n\n';
  resp += 'Quand le jeune répond, rappelle build_cv avec ID + résumé cumulatif.';
  return [{ json: { response: resp, phase: 'collect', needs_critique: false } }];
}

// === PHASE GENERATE ===
const score = result.koda_score?.total || 0;

if (score < 70) {
  // Needs improvement — build critique prompt for Haiku
  const critiquePrompt = `Ce CV a obtenu un score de ${score}/100. Voici les feedbacks :
FORMAT (${result.koda_score?.format?.score}/25) : ${result.koda_score?.format?.feedback}
CONTENU (${result.koda_score?.contenu?.score}/25) : ${result.koda_score?.contenu?.feedback}
MOTS-CLÉS (${result.koda_score?.mots_cles?.score}/25) : ${result.koda_score?.mots_cles?.feedback}
IMPACT (${result.koda_score?.impact?.score}/25) : ${result.koda_score?.impact?.feedback}

Amélioration prioritaire : ${result.koda_score?.top_improvement}

CV actuel en JSON :
${JSON.stringify(result, null, 2).substring(0, 3000)}

AMÉLIORE ce CV en appliquant les feedbacks. Retourne le CV complet en JSON amélioré (même structure), avec un nouveau koda_score.`;

  return [{ json: {
    phase: 'generate',
    needs_critique: true,
    cv_json: result,
    koda_score: result.koda_score,
    critique_system: 'Tu es un expert CV. Améliore ce CV junior en appliquant les critiques. Garde la même structure JSON. Ne mens pas, ne fabrique rien. Valorise mieux ce qui existe.',
    critique_prompt: critiquePrompt
  } }];
}

// Score >= 70 — CV is good enough
return [{ json: {
  phase: 'generate',
  needs_critique: false,
  cv_json: result,
  koda_score: result.koda_score
} }];

const evalData = $('🔍 Évaluer et Router').first().json;

// If collect phase, just return the question
if (evalData.phase === 'collect' || evalData.phase === 'error') {
  return [{ json: { response: evalData.response, phase: evalData.phase } }];
}

// Get the CV — either improved by Haiku or original from Sonnet
let cv = evalData.cv_json;
let score = evalData.koda_score;

if (evalData.needs_critique) {
  try {
    const haikuResp = $('🧠 Haiku Critique').first().json;
    const text = haikuResp.content?.[0]?.text || '';
    const improved = JSON.parse(text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim());
    if (improved.prenom_nom) {
      cv = improved;
      score = improved.koda_score || score;
    }
  } catch(e) { /* keep original */ }
}

// Build HTML
let h = '<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><style>';
h += '@page{size:A4;margin:0}*{margin:0;padding:0;box-sizing:border-box}';
h += 'body{font-family:Georgia,"Times New Roman",serif;font-size:10.5pt;line-height:1.4;color:#1a1a1a;width:210mm;min-height:297mm;padding:18mm 20mm 15mm 20mm}';
h += '.hdr{text-align:center;margin-bottom:6mm}.hdr h1{font-size:22pt;font-weight:bold;letter-spacing:1.5px;margin-bottom:2mm}';
h += '.hdr .ct{font-size:9.5pt;color:#444;line-height:1.6}.hdr .ct a{color:#1a5276;text-decoration:none}';
h += '.hdr .tt{font-size:11pt;font-style:italic;color:#1a5276;margin-top:3mm}';
h += '.st{text-align:center;font-size:11pt;font-weight:bold;letter-spacing:2px;text-transform:uppercase;margin-top:5mm;margin-bottom:3mm;border-top:1px solid #1a1a1a;border-bottom:1px solid #1a1a1a;padding:1.5mm 0}';
h += '.pr{font-size:10pt;text-align:justify;line-height:1.5;margin-bottom:2mm;color:#333}';
h += '.ex{margin-bottom:4mm}.exh{display:flex;justify-content:space-between;align-items:baseline;margin-bottom:1mm}';
h += '.ext{font-weight:bold;font-size:10.5pt;text-transform:uppercase}.exd{font-style:italic;font-size:9pt;color:#555}';
h += '.exl{font-style:italic;font-size:9.5pt;color:#555;margin-bottom:1.5mm}';
h += '.ca{margin-bottom:1mm;font-size:10pt;line-height:1.45;text-align:justify}.cn{font-weight:bold}';
h += '.fm{margin-bottom:3mm}.fmh{display:flex;justify-content:space-between;align-items:baseline}';
h += '.fmt{font-weight:bold;font-size:10.5pt;text-transform:uppercase}.fmd{font-style:italic;font-size:9pt;color:#555}';
h += '.fml{font-style:italic;font-size:9.5pt;color:#555}.fmdt{font-size:9.5pt;color:#333;margin-top:0.5mm}';
h += '.cl{margin-bottom:1.5mm;font-size:10pt;line-height:1.5}.cc{font-weight:bold}';
h += '.it{font-size:10pt;color:#333}';
h += '</style></head><body>';

h += '<div class="hdr"><h1>' + (cv.prenom_nom||'') + '</h1>';
h += '<div class="ct">';
if (cv.telephone) h += 'Téléphone : ' + cv.telephone + '<br>';
if (cv.email && cv.email !== 'non renseigné') h += 'Email : <a href="mailto:'+cv.email+'">'+cv.email+'</a>';
h += '</div>';
if (cv.titre) h += '<div class="tt">' + cv.titre + '</div>';
h += '</div>';

if (cv.profil) { h += '<div class="st">Profil</div><div class="pr">' + cv.profil + '</div>'; }

if (cv.experiences?.length > 0) {
  h += '<div class="st">Expérience</div>';
  for (const e of cv.experiences) {
    h += '<div class="ex"><div class="exh"><span class="ext">'+(e.poste||'')+'</span><span class="exd">'+(e.dates||'')+'</span></div>';
    if (e.lieu) h += '<div class="exl">'+e.lieu+'</div>';
    if (e.categories) { for (const c of e.categories) { h += '<div class="ca"><span class="cn">'+c.nom+' : </span>'+c.detail+'</div>'; } }
    h += '</div>';
  }
}

if (cv.formations?.length > 0) {
  h += '<div class="st">Formation</div>';
  for (const f of cv.formations) {
    h += '<div class="fm"><div class="fmh"><span class="fmt">'+(f.diplome||'')+'</span><span class="fmd">'+(f.dates||'')+'</span></div>';
    if (f.lieu) h += '<div class="fml">'+f.lieu+'</div>';
    if (f.detail) h += '<div class="fmdt">'+f.detail+'</div>';
    h += '</div>';
  }
}

if (cv.competences?.length > 0) {
  h += '<div class="st">Compétences</div>';
  for (const c of cv.competences) { h += '<div class="cl"><span class="cc">'+c.categorie+' : </span>'+c.detail+'</div>'; }
}

if (cv.centres_interet) { h += '<div class="st">Centres d\'intérêt</div><div class="it">'+cv.centres_interet+'</div>'; }
h += '</body></html>';

// Build summary for agent
let summary = 'CV GÉNÉRÉ ! Koda Score : ' + (score?.total || '?') + '/100\n\n';
summary += 'Titre : ' + (cv.titre || '') + '\n';
if (cv.experiences) { summary += '\nExpériences :\n'; cv.experiences.forEach(e => { summary += '- ' + e.poste + ' (' + (e.dates||'') + ')\n'; }); }
if (cv.formations) { summary += '\nFormations :\n'; cv.formations.forEach(f => { summary += '- ' + f.diplome + '\n'; }); }
if (score) {
  summary += '\nDétail score :\n';
  summary += '- Format : ' + (score.format?.score||'?') + '/25\n';
  summary += '- Contenu : ' + (score.contenu?.score||'?') + '/25\n';
  summary += '- Mots-clés : ' + (score.mots_cles?.score||'?') + '/25\n';
  summary += '- Impact : ' + (score.impact?.score||'?') + '/25\n';
  summary += '\nAmélioration suggérée : ' + (score.top_improvement || 'Aucune') + '\n';
}
summary += '\nPrésente ce récap au jeune avec le score et demande si c\'est bon.';

return [{ json: { response: summary, phase: 'generate', cv_html: h, cv_json: cv, koda_score: score } }];

// Construire la réponse finale avec l'URL du CV
const htmlData = $('🎨 Construire HTML final').first().json;
const saveResult = $('💾 Sauver CV dans Postgres').first().json;

const cvId = saveResult.id || 'error';
const cvUrl = 'https://jgqalweqpifycuhootmx.supabase.co/functions/v1/serve-cv?id=' + cvId;

return [{ json: {
  response: htmlData.response,
  phase: htmlData.phase,
  cv_json: htmlData.cv_json,
  cv_html: htmlData.cv_html,
  koda_score: htmlData.koda_score,
  cv_url: cvUrl,
  cv_id: cvId
} }];

// Préparer le HTML pour envoi à Gotenberg
const htmlData = $('🎨 Construire HTML final').first().json;

if (htmlData.phase !== 'generate' || !htmlData.cv_html) {
  return [{ json: { ...htmlData, pdf_base64: null, skip_pdf: true } }];
}

// Encoder le HTML en base64 manuellement (pas de Buffer en sandbox)
function utf8ToBase64(str) {
  const utf8 = unescape(encodeURIComponent(str));
  let base64 = '';
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  let i = 0;
  while (i < utf8.length) {
    const a = utf8.charCodeAt(i++);
    const b = i < utf8.length ? utf8.charCodeAt(i++) : 0;
    const c = i < utf8.length ? utf8.charCodeAt(i++) : 0;
    const triplet = (a << 16) | (b << 8) | c;
    base64 += chars[(triplet >> 18) & 63];
    base64 += chars[(triplet >> 12) & 63];
    base64 += i > utf8.length + 1 ? '=' : chars[(triplet >> 6) & 63];
    base64 += i > utf8.length ? '=' : chars[triplet & 63];
  }
  return base64;
}

const htmlBase64 = utf8ToBase64(htmlData.cv_html);

return [{
  json: { ...htmlData, skip_pdf: false },
  binary: {
    file: {
      data: htmlBase64,
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

// Extraire le PDF en base64 depuis la réponse binaire de Gotenberg
const htmlData = $('📦 Préparer HTML pour PDF').first().json;
const binaryData = $input.first().binary;

let pdfBase64 = null;

if (binaryData && binaryData.data) {
  pdfBase64 = binaryData.data.data || '';
} else if (binaryData && binaryData.file) {
  pdfBase64 = binaryData.file.data || '';
}

// Chercher dans toutes les clés binary
if (!pdfBase64) {
  const binKeys = Object.keys(binaryData || {});
  for (const key of binKeys) {
    if (binaryData[key] && binaryData[key].data) {
      pdfBase64 = binaryData[key].data;
      break;
    }
  }
}

return [{ json: {
  ...htmlData,
  pdf_base64: pdfBase64,
  pdf_error: pdfBase64 ? null : 'PDF non généré'
} }];
